mapper.select:
SELECT o.*, buyer.nickname AS buyer_nickname, buyer.avatar AS buyer_avatar, seller.nickname AS seller_nickname, seller.avatar AS seller_avatar, p.title AS product_title, p.images AS product_images FROM orders o LEFT JOIN sys_user buyer ON o.buyer_id = buyer.id LEFT JOIN sys_user seller ON o.seller_id = seller.id LEFT JOIN product p ON o.product_id = p.id WHERE o.deleted = 0
AND o.buyer_id = #{buyerId}
AND o.seller_id = #{sellerId}
AND o.status = #{status}
ORDER BY o.create_time DESC
